mapper.select:
SELECT ID, STANDARD, STYLE, STYLE_TEXT, VERSION, MERGE_WAY, SUM_WAY, QUARTER, END_TERM, START_DT, END_DT FROM FORMAL WHERE (VERSION LIKE '%' || #{version} || '%' OR STYLE LIKE '%' || #{version} || '%' OR STYLE_TEXT LIKE '%' || #{version} || '%')
AND ID = #{id}
ORDER BY UPDATE_DT DESC

SELECT STYLE, VERSION, START_DT, END_DT, TO_CHAR(UPDATE_DT, 'YYYY-MM-DD HH24:MI') AS UPDATE_DT FROM FORMAL WHERE ((STYLE = #{style} AND VERSION = #{version}) OR (STYLE = #{style} AND (TO_DATE(START_DT,'YYYY-MM') <= TO_DATE(#{endDt},'YYYY-MM') AND TO_DATE(END_DT,'YYYY-MM') >= TO_DATE(#{startDt},'YYYY-MM'))))
AND ID != #{id}
AND ROWNUM = 1
